const query = $('Webhook').item.json.body.query ?? '';

let memories = [];

if (items.length > 0 && items[0]?.json?.title !== undefined) {
  memories = items.map(item => item.json);
} else if (items.length > 0 && Array.isArray(items[0]?.json?.body)) {
  memories = items[0].json.body;
} else if (items.length > 0 && Array.isArray(items[0]?.json?.data)) {
  memories = items[0].json.data;
} else if (items.length > 0 && Array.isArray(items[0]?.json)) {
  memories = items[0].json;
}

memories = memories.filter(memory => memory && (
  memory.title !== undefined ||
  memory.category !== undefined ||
  memory.source !== undefined ||
  memory.content !== undefined
));

const context = memories.length
  ? memories.map((memory, index) => {
      const title = memory.title ?? '';
      const category = memory.category ?? '';
      const source = memory.source ?? '';
      const content = memory.content ?? '';

      return `Memory ${index + 1}\nTitle: ${title}\nCategory: ${category}\nSource: ${source}\nContent:\n${content}`;
    }).join('\n\n---\n\n')
  : 'No relevant memories were retrieved.';

const prompt = `You are answering a user question using retrieved memory context from OpenBrain.\n\nRules:\n- Use only the provided memory context.\n- If the context does not contain enough information, say that you do not have enough memory context to answer confidently.\n- Be concise and direct.\n\nUser question:\n${query}\n\nMemory context:\n${context}\n\nAnswer:`;

return [{
  json: {
    query,
    context,
    prompt
  }
}];
